+
+  // Analytics
+  async getActiveUsers(since: Date): Promise&lt;number&gt; {
+    return this.db.users.count({ lastLoginAt: { $gte: since } });
+  }
+
+  async getUsersByRole(role: User[&#39;role&#39;]): Promise&lt;User[]&gt; {
+    return this.db.users.findMany({ role });
+  }
