+
+/* ========================================
+   Virtual Scrolling
+   ======================================== */
+
+/* Virtual list container */
+.virtual-list-inner {
+    contain: layout style;
+}
+
+/* Results list with virtual scrolling */
+.results-list {
+    position: relative;
+}
+
+.results-list.virtual-scroll {
+    height: calc(100vh - 300px);
+    min-height: 400px;
+    overflow: auto;
+}
+
+/* Fixed height result cards for virtual list */
+.results-list .result-card {
+    box-sizing: border-box;
+    overflow: hidden;
+}
+
+/* Virtual list result card adjustments */
+.results-list [data-virtual-index] .result-card {
+    margin: 0;
+    height: 100%;
+}
+
+/* Messages list with virtual scrolling */
+.messages-list.virtual-messages {
+    height: calc(100vh - 200px);
+    min-height: 400px;
+    overflow: auto;
+    position: relative;
+}
+
+/* Virtual indicator badge */
+.virtual-indicator {
+    font-size: 0.75rem;
+    padding: 0 var(--space-xs);
+    color: var(--color-warning);
+    cursor: help;
+}
+
+/* Loading indicator for lazy loading */
+.loading-more {
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    padding: var(--space-lg);
+    color: var(--color-text-muted);
+}
+
+/* Scroll shadows for virtualized lists */
+.scroll-shadow-top,
+.scroll-shadow-bottom {
+    position: absolute;
+    left: 0;
+    right: 0;
+    height: 20px;
+    pointer-events: none;
+    z-index: 10;
+}
+
+.scroll-shadow-top {
+    top: 0;
+    background: linear-gradient(to bottom, var(--color-bg) 0%, transparent 100%);
+}
+
+.scroll-shadow-bottom {
+    bottom: 0;
+    background: linear-gradient(to top, var(--color-bg) 0%, transparent 100%);
+}
+
+/* Flash highlight animation for scrolled-to items */
+@keyframes highlight-flash {
+    0% { background-color: rgba(59, 130, 246, 0.3); }
+    100% { background-color: transparent; }
+}
+
+.highlight-flash {
+    animation: highlight-flash 2s ease-out;
+}
+
+/* Performance optimization: GPU acceleration for virtual items */
+.virtual-list-inner > * {
+    will-change: transform;
+}
+
+/* ========================================
+   Conversation Viewer (populated by conversation.js)
+   ======================================== */
+.conversation-container {
+    max-width: 900px;
+    margin: 0 auto;
+}
+
+.conversation-header {
+    display: flex;
+    align-items: center;
+    gap: var(--space-md);
+    margin-bottom: var(--space-lg);
+    padding-bottom: var(--space-lg);
